  5	  GraphDefinition,
  6	  GraphEdgeWrapper,
  7	  GraphNodeData,
  8	  NodeType,
  9	  DestService,
 10	  ProtocolTraffic,
 11	  SEInfo
 12	} from '../../types/Graph';
 13	import { RenderComponentScroll } from '../Nav/Page';
 14	import { MetricsObjectTypes } from '../../types/Metrics';
 15	import { GraphDataSource } from 'services/GraphDataSource';
 16	import { DurationInSeconds, TimeInMilliseconds } from 'types/Common';
 17	import * as FilterHelper from '../FilterList/FilterHelper';
 18	import * as TrafficListFilters from './FiltersAndSorts';
 19	import { KialiAppState } from '../../store/Store';
 20	import { connect } from 'react-redux';
 21	import { durationSelector } from '../../store/Selectors';
 22	import { HealthAnnotationType } from '../../types/HealthAnnotation';
 23	import { TrafficListComponent } from 'components/TrafficList/TrafficListComponent';
 24	import { KioskElement } from '../Kiosk/KioskElement';
 25	import { TimeDurationModal } from '../Time/TimeDurationModal';
 26	import { TimeDurationIndicator } from '../Time/TimeDurationIndicator';
 27	
 28	export interface AppNode {
 29	  id: string;
 30	  type: NodeType.APP;
 31	  namespace: string;
 32	  name: string;
 33	  version: string;
 34	  isInaccessible: boolean;
 35	  cluster?: string;
 36	}
 37	
 38	export interface WorkloadNode {
 39	  id: string;
 40	  type: NodeType.WORKLOAD;
 41	  namespace: string;
 42	  name: string;
 43	  isInaccessible: boolean;
 44	  healthAnnotation?: HealthAnnotationType;
 45	  cluster?: string;
 46	}
 47	
 48	export interface ServiceNode {
 49	  id: string;
 50	  type: NodeType.SERVICE;
 51	  namespace: string;
 52	  name: string;
 53	  isInaccessible: boolean;
 54	  isServiceEntry?: SEInfo;
 55	  destServices?: DestService[];
 56	  healthAnnotation?: HealthAnnotationType;
 57	  cluster?: string;
 58	}
 59	
 60	export type TrafficNode = AppNode | ServiceNode | WorkloadNode;
 61	
 62	export type TrafficDirection = 'inbound' | 'outbound';
 63	
 64	export interface TrafficItem {
 65	  direction: TrafficDirection;
 66	  node: TrafficNode;
 67	  proxy?: TrafficItem;
 68	  traffic: ProtocolTraffic;
 69	  mTLS?: number;
 70	}
 71	
 72	type ReduxProps = {
 73	  duration: DurationInSeconds;
 74	};
 75	
 76	type TrafficDetailsProps = ReduxProps & {
 77	  itemName: string;
 78	  itemType: MetricsObjectTypes;
 79	  lastRefreshAt: TimeInMilliseconds;
 80	  namespace: string;
 81	  cluster?: string;
 82	};
 83	
 84	type TrafficDetailsState = {
 85	  isTimeOptionsOpen: boolean;
 86	  traffic: TrafficItem[];
 87	};
 88	
 89	class TrafficDetailsComponent extends React.Component<TrafficDetailsProps, TrafficDetailsState> {
 90	  private graphDataSource = new GraphDataSource();
 91	
 92	  constructor(props: TrafficDetailsProps) {
 93	    super(props);
 94	    this.state = {
 95	      isTimeOptionsOpen: false,
 96	      traffic: []
 97	    };
 98	  }
 99	
100	  componentDidMount() {
101	    this.graphDataSource.on('fetchSuccess', this.graphDsFetchSuccess);
102	    this.graphDataSource.on('fetchError', this.graphDsFetchError);
103	    this.fetchDataSource();
104	  }
105	
106	  componentWillUnmount() {
107	    this.graphDataSource.removeListener('fetchSuccess', this.graphDsFetchSuccess);
108	    this.graphDataSource.removeListener('fetchError', this.graphDsFetchError);
109	  }
110	
111	  componentDidUpdate(prevProps: TrafficDetailsProps) {
112	    const durationChanged = prevProps.duration !== this.props.duration;
113	    const itemNameChanged = prevProps.itemName !== this.props.itemName;
114	    const itemTypeChanged = prevProps.itemType !== this.props.itemType;
115	    const namespaceChanged = prevProps.namespace !== this.props.namespace;
116	    const refreshChanged = prevProps.lastRefreshAt !== this.props.lastRefreshAt;
117	
118	    if (durationChanged || itemNameChanged || itemTypeChanged || namespaceChanged || refreshChanged) {
119	      this.fetchDataSource();
120	    }
121	  }
122	
123	  render() {
124	    return (
125	      <>
126	        <RenderComponentScroll>
127	          <Grid>
128	            <GridItem span={12}>
129	              <Card>
130	                <CardBody>
131	                  <Toolbar style={{ padding: 0, width: '100%' }}>
132	                    <ToolbarGroup>
133	                      <KioskElement>
134	                        <ToolbarItem style={{ marginLeft: 'auto' }}>
135	                          <TimeDurationIndicator isDuration={true} onClick={this.toggleTimeOptionsVisibility} />
136	                        </ToolbarItem>
137	                      </KioskElement>
138	                    </ToolbarGroup>
139	                  </Toolbar>
140	                  <TrafficListComponent
141	                    currentSortField={FilterHelper.currentSortField(TrafficListFilters.sortFields)}
142	                    isSortAscending={FilterHelper.isCurrentSortAscending()}
143	                    trafficItems={this.state.traffic}
144	                  />
145	                </CardBody>
146	              </Card>
147	            </GridItem>
148	          </Grid>
149	        </RenderComponentScroll>
150	        <TimeDurationModal
151	          customDuration={false}
152	          isOpen={this.state.isTimeOptionsOpen}
153	          onConfirm={this.toggleTimeOptionsVisibility}
154	          onCancel={this.toggleTimeOptionsVisibility}
155	        />
156	      </>
157	    );
158	  }
159	
160	  private fetchDataSource = () => {
161	    switch (this.props.itemType) {
162	      case MetricsObjectTypes.SERVICE: {
163	        const params = this.graphDataSource.fetchForServiceParams(
164	          this.props.duration,
165	          this.props.namespace,
166	          this.props.itemName,
167	          this.props.cluster
168	        );
169	        params.includeHealth = false;
170	        params.showSecurity = true;
171	        this.graphDataSource.fetchGraphData(params);
172	        break;
173	      }
174	      case MetricsObjectTypes.WORKLOAD: {
175	        const params = this.graphDataSource.fetchForWorkloadParams(
176	          this.props.duration,
177	          this.props.namespace,
178	          this.props.itemName,
179	          this.props.cluster
180	        );
181	        params.includeHealth = false;
182	        params.injectServiceNodes = false;
183	        params.showSecurity = true;
184	        this.graphDataSource.fetchGraphData(params);
185	        break;
186	      }
187	      case MetricsObjectTypes.APP: {
188	        const params = this.graphDataSource.fetchForAppParams(
189	          this.props.duration,
190	          this.props.namespace,
191	          this.props.itemName,
192	          this.props.cluster
193	        );
194	        params.includeHealth = false;
195	        params.injectServiceNodes = false;
196	        params.showSecurity = true;
197	        this.graphDataSource.fetchGraphData(params);
198	        break;
199	      }
200	    }
201	  };
202	
203	  private graphDsFetchSuccess = () => {
204	    this.processTrafficData(this.graphDataSource.graphDefinition);
205	  };
206	
207	  private graphDsFetchError = (errorMessage: string | null) => {
208	    if (errorMessage !== '') {
209	      errorMessage = 'Could not fetch traffic data: ' + errorMessage;
210	    } else {
211	      errorMessage = 'Could not fetch traffic data.';
212	    }
213	
214	    AlertUtils.addError(errorMessage);
215	  };
216	
217	  private buildTrafficNode = (prefix: 'in' | 'out', node: GraphNodeData): TrafficNode => {
218	    // given restrictions on fetch options the node type should be either App, Workload or [outbound] service
219	    switch (node.nodeType) {
220	      case NodeType.APP:
221	        return {
222	          id: `${prefix}-${node.id}`,
223	          type: node.nodeType,
224	          namespace: node.namespace,
225	          cluster: node.cluster,
226	          name: node.app || 'unknown',
227	          version: node.version || '',
228	          isInaccessible: node.isInaccessible || false
229	        };
230	      case NodeType.SERVICE:
231	        return {
232	          id: `${prefix}-${node.id}`,
233	          type: node.nodeType,
234	          namespace: node.namespace,
235	          cluster: node.cluster,
236	          name: node.service || 'unknown',
237	          isServiceEntry: node.isServiceEntry,
238	          isInaccessible: node.isInaccessible || false,
239	          destServices: node.destServices,
240	          healthAnnotation: node.hasHealthConfig
241	        };
242	      default:
243	        return {
244	          id: `${prefix}-${node.id}`,
245	          type: NodeType.WORKLOAD,
246	          namespace: node.namespace,
247	          cluster: node.cluster,
248	          name: node.workload || 'unknown',
249	          isInaccessible: node.isInaccessible || false,
250	          healthAnnotation: node.hasHealthConfig
251	        };
252	    }
253	  };
254	
255	  private processTraffic = (
256	    edges: GraphEdgeWrapper[],
257	    nodes: { [key: string]: GraphNodeData },
258	    myNode: GraphNodeData
259	  ) => {
260	    const traffic: TrafficItem[] = [];
261	
262	    edges.forEach(edge => {
263	      const sourceNode = nodes['id-' + edge.data.source];
264	      const targetNode = nodes['id-' + edge.data.target];
265	      if (myNode.id === edge.data.source) {
266	        const trafficItem: TrafficItem = {
267	          direction: 'outbound',
268	          node: this.buildTrafficNode('out', targetNode),
269	          traffic: edge.data.traffic!,
270	          mTLS: edge.data.isMTLS
271	        };
272	        traffic.push(trafficItem);
273	      } else if (myNode.id === edge.data.target) {
274	        const trafficItem: TrafficItem = {
275	          direction: 'inbound',
276	          node: this.buildTrafficNode('in', sourceNode),
277	          traffic: edge.data.traffic!,
278	          mTLS: edge.data.isMTLS
279	        };
280	        traffic.push(trafficItem);
281	      }
282	    });
283	
284	    return { traffic: traffic };
285	  };
286	
287	  private processTrafficData = (traffic: GraphDefinition | null) => {
288	    if (
289	      !traffic ||
290	      !traffic.elements.nodes ||
291	      !traffic.elements.edges ||
292	      traffic.elements.nodes.length === 0 ||
293	      traffic.elements.edges.length === 0
294	    ) {
295	      this.setState({ traffic: [] });
296	      return;
297	    }
298	
299	    // Index nodes by id and find the node of the queried item
300	    const nodes: { [key: string]: GraphNodeData } = {};
301	    let myNode: GraphNodeData = { id: '', nodeType: NodeType.UNKNOWN, cluster: '', namespace: '' };
302	
303	    traffic.elements.nodes.forEach(element => {
304	      // Ignore box nodes. They are not relevant for the traffic list because we
305	      // are interested in the actual apps.
306	      if (!element.data.isBox) {
307	        nodes['id-' + element.data.id] = element.data;
308	        if (element.data.namespace) {
309	          const isMyWorkload =
310	            this.props.itemType === MetricsObjectTypes.WORKLOAD &&
311	            element.data.nodeType === NodeType.WORKLOAD &&
312	            this.props.itemName === element.data.workload;
313	          const isMyApp =
314	            this.props.itemType === MetricsObjectTypes.APP &&
315	            element.data.nodeType === NodeType.APP &&
316	            this.props.itemName === element.data.app;
317	          const isMyService =
318	            this.props.itemType === MetricsObjectTypes.SERVICE &&
319	            element.data.nodeType === NodeType.SERVICE &&
320	            this.props.itemName === element.data.service;
321	
322	          if (isMyWorkload || isMyApp || isMyService) {
323	            myNode = element.data;
324	          }
325	        }
326	      }
327	    });
328	
329	    if (myNode.id === '') {
330	      // Graph endpoint didn't return a graph for the current node.
331	      this.setState({ traffic: [] });
332	      return;
333	    }
334	
335	    // Process the direct inbound/outbound traffic to/from the item of interest.
336	    this.setState(this.processTraffic(traffic.elements.edges!, nodes, myNode));
337	  };
338	
339	  private toggleTimeOptionsVisibility = () => {
340	    this.setState(prevState => ({ isTimeOptionsOpen: !prevState.isTimeOptionsOpen }));
341	  };
342	}
343	
344	const mapStateToProps = (state: KialiAppState) => {
345	  return {
346	    duration: durationSelector(state)
347	  };
348	};
349	
350	export const TrafficDetails = connect(mapStateToProps)(TrafficDetailsComponent);

